INSERT INTO questions VALUES(1,1,'CH','利用计算机对文本、图形图像、影视频等进行处理，这属于计算机在_____方面的应用。','[{"label": "A", "value": "科学计算"}, {"label": "B", "value": "数据处理"}, {"label": "C", "value": "生产控制"}, {"label": "D", "value": "模式识别"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(2,2,'CH','在计算机科学研究范畴内，下列关于数据的说法错误的是_____。','[{"label": "A", "value": "数据是信息的载体"}, {"label": "B", "value": "数据是计算机识别、存储、加工的对象"}, {"label": "C", "value": "数据专指用于科学计算的数值型数据"}, {"label": "D", "value": "数据是人们提取信息、做出决策的重要依据"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(3,3,'CH','在计算机科学研究范畴内，下列关于数据的说法正确的是_____。','[{"label": "A", "value": "数据就是信息"}, {"label": "B", "value": "数据不经过加工也可以称作信息"}, {"label": "C", "value": "数据就是知识"}, {"label": "D", "value": "数据经过解释成为信息，并对接收者的行为产生影响"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(4,4,'CH','在计算机科学研究范畴内，下列关于数据的描述正确的是_____。','[{"label": "A", "value": "数据无法用于描述事物"}, {"label": "B", "value": "只有用于统计的数值才是数据"}, {"label": "C", "value": "数据是不能被加工处理的"}, {"label": "D", "value": "数据可以是字符、图像、音频和视频"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(5,5,'CH',replace('计算机可以识别、存储和加工的数据有_____。\n\n①数值 ②字符 ③图像 ④音视频','\n',char(10)),'[{"label": "A", "value": "①"}, {"label": "B", "value": "①②"}, {"label": "C", "value": "①②③"}, {"label": "D", "value": "①②③④"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(6,6,'CH','所有能输入到计算机中并能被计算机程序处理的对象被称为_____。','[{"label": "A", "value": "数据"}, {"label": "B", "value": "信息"}, {"label": "C", "value": "知识"}, {"label": "D", "value": "智慧"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(7,7,'CH','下面不属于信息特征的是_____。','[{"label": "A", "value": "载体依附性"}, {"label": "B", "value": "价值性"}, {"label": "C", "value": "时效性"}, {"label": "D", "value": "独享性"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(8,8,'CH','天气预报、市场信息都会随时间的推移而变化，这体现了信息的_____特征。','[{"label": "A", "value": "载体依附性"}, {"label": "B", "value": "共享性"}, {"label": "C", "value": "时效性"}, {"label": "D", "value": "必要性"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(9,9,'CH','古人将文字、符号刻在龟甲上，这主要体现了信息的_____特征。','[{"label": "A", "value": "可加工性"}, {"label": "B", "value": "时效性"}, {"label": "C", "value": "载体依附性"}, {"label": "D", "value": "真伪性"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(10,10,'CH','小明将杂志上刊登的一篇文章用智能处理软件识别后，将文档保存在计算机中。结合该处理过程，下列叙述中正确的是_____。','[{"label": "A", "value": "文章保存到计算机后，由于载体发生改变，信息也随之改变"}, {"label": "B", "value": "信息可以通过多种技术手段进行加工和处理"}, {"label": "C", "value": "可以将扫描后获得的稿件以自己的名义向其它杂志重新投稿"}, {"label": "D", "value": "计算机中的信息可以复制，因此只有计算机中的信息才具有共享性"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(11,11,'CH','你有一个苹果，我也有一个苹果，彼此交换一下，我们仍然是各有一个苹果；但你有一种思想，我有一种思想，彼此交换，我们就都有了两种思想，甚至更多。这体现了信息的_____特征。','[{"label": "A", "value": "载体依附性"}, {"label": "B", "value": "共享性"}, {"label": "C", "value": "时效性"}, {"label": "D", "value": "必要性"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(12,12,'CH','下列有关信息的说法正确的是_____。','[{"label": "A", "value": "计算机内部可以使用十六进制处理信息"}, {"label": "B", "value": "计算机网络属于信息表达方式"}, {"label": "C", "value": "扫描二维码属于信息的编码"}, {"label": "D", "value": "信息可以用来消除接收者某种认识上的不确定性"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(13,13,'CH','下列有关信息的说法正确的是_____。','[{"label": "A", "value": "用计算机处理信息的技术才是信息技术"}, {"label": "B", "value": "微信公众号上发布的信息，肯定是真实有效的"}, {"label": "C", "value": "使用手机扫描二维码的过程，属于信息的获取"}, {"label": "D", "value": "通过无线网络传输的信息不依附任何载体"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(14,14,'CH','"珠穆朗玛峰（简称\''珠峰\''）是喜马拉雅山脉的主峰，也是世界海拔最高的山峰，位于中国与尼泊尔的边境线上。珠峰的高度，尼泊尔等国采用的雪盖高（总高）是8848米，与中国绘制工作者于1975年测量的值一致；中国采用的是2005年中国国家测绘局测量的岩面高（裸高，即地质高度）约8844米，作为中国统一采用的标准数据一直沿用至今。"结合上述事例，下列对于数据、信息、知识的描述，正确的是_____。','[{"label": "A", "value": "若在纸上单独书写\"8848\"这几个数字，它就已经被赋予了一定的意义"}, {"label": "B", "value": "\"珠峰峰顶海拔过高，不宜人类居住。\"这体现了人类的智慧"}, {"label": "C", "value": "当人们看到海拔8000多米的高度时，会联想到缺氧、寒冷等词汇，这是知识的体现"}, {"label": "D", "value": "不同国籍的人引用珠峰高度时可能会采用不同的数据，这体现了信息的真伪性"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(15,15,'CH','下列关于数据、信息与知识的说法中，错误的是_____。','[{"label": "A", "value": "数据是信息的载体"}, {"label": "B", "value": "数据处理后转换为信息"}, {"label": "C", "value": "信息可以内化为知识"}, {"label": "D", "value": "信息是知识的载体"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(16,16,'CH','有"成年人清晨安静状态下的口腔正常温度是36.3\--37.2℃"、"38"和"小明的口腔温度是38℃"三种描述，这三种描述分别是_____。','[{"label": "A", "value": "信息、数据、知识"}, {"label": "B", "value": "知识、信息、数据"}, {"label": "C", "value": "数据、信息、知识"}, {"label": "D", "value": "知识、数据、信息"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(17,17,'CH','国家有关部门根据学生体质健康数据制定了《国家学生体质健康标准》，其中高一男生的正常体重指数为16.5\--23.2，这属于_____。','[{"label": "A", "value": "数据"}, {"label": "B", "value": "信息"}, {"label": "C", "value": "知识"}, {"label": "D", "value": "智慧"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(18,18,'CH','人们在社会实践中所获得的认识和经验的总和被称为_____。','[{"label": "A", "value": "数据"}, {"label": "B", "value": "信息"}, {"label": "C", "value": "知识"}, {"label": "D", "value": "智慧"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(19,19,'CH','下列关于大数据特征的说法中，错误的是_____。','[{"label": "A", "value": "数据规模大"}, {"label": "B", "value": "数据类型多样"}, {"label": "C", "value": "数据处理速度快"}, {"label": "D", "value": "数据价值密度高"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(20,20,'CH','下列关于大数据的说法中，错误的是_____。','[{"label": "A", "value": "大数据的多样性是指数据种类繁多，既有传统的关系型数据，还包括网页、搜索索引、图像音视频和地理位置等数据"}, {"label": "B", "value": "\"大数据\"与\"传统数据\"只是在规模上存在不同，在采集方式和分析方法上是相同的"}, {"label": "C", "value": "大数据技术指对采集来的巨量数据资源进行提取、存储、分析和表达的技术"}, {"label": "D", "value": "大数据预处理技术能够提高数据质量、降低数据计算的复杂度"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(21,21,'CH','大数据处理的一般过程是_____。','[{"label": "A", "value": "采集\\--统计\\--清洗\\--挖掘"}, {"label": "B", "value": "采集\\--清洗\\--统计\\--挖掘"}, {"label": "C", "value": "采集\\--挖掘\\--清洗\\--统计"}, {"label": "D", "value": "采集\\--清洗\\--挖掘\\--统计"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(22,22,'CH','下列描述中，不属于大数据应用的是_____。','[{"label": "A", "value": "电商网站通过分析客户消费数据，实现个性化商品推荐"}, {"label": "B", "value": "利用智能手机中的导航地图可以了解实时路况，规划最快捷的出行路线"}, {"label": "C", "value": "张老师对所教班级学生体质数据进行分析，给学生提出锻炼建议"}, {"label": "D", "value": "有关部门对公共场所进行监控，协助搜捕犯罪嫌疑人"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(23,23,'CH','大数据包括传统的关系型数据，还包含网页、搜索索引、图像、音视频和地理位置等数据。这体现了大数据的_____特征。','[{"label": "A", "value": "巨量性"}, {"label": "B", "value": "多样性"}, {"label": "C", "value": "迅变性"}, {"label": "D", "value": "价值性"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(24,24,'CH','大数据与传统数据的差别体现在_____。','[{"label": "A", "value": "采集方式不同"}, {"label": "B", "value": "分析方法不同"}, {"label": "C", "value": "数据规模不同"}, {"label": "D", "value": "以上都是"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(25,25,'CH',replace('下列应用中，体现了人工智能技术的有_____。\n\n（1）机器人通过语音与人交流\n\n（2）饮水机根据水温自动加热\n\n（3）宾馆通过专用系统进行人脸识别，核实住宿人员身份\n\n（4）计算机程序根据输入的三条边长自动计算三角形面积\n\n（5）停车管理系统通过拍摄识别车牌号码，并用语音进行播报','\n',char(10)),'[{"label": "A", "value": "(1)(2)(3)"}, {"label": "B", "value": "(1)(3)(5)"}, {"label": "C", "value": "(2)(4)(5)"}, {"label": "D", "value": "(3)(4)(5)"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(26,26,'CH','人们在严格筛选古今中医临床经验数据的基础上建立计算机数据库，遵循中医辨证施治原理，开发出高度智能化的医学应用软件，再现古代名医的诊治专长，还可实现古今临床名医的联合会诊。这样的应用属于_____。','[{"label": "A", "value": "远程交流"}, {"label": "B", "value": "专家系统"}, {"label": "C", "value": "模式识别"}, {"label": "D", "value": "机器翻译"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(27,27,'CH',replace('指纹考勤机的工作原理是通过提取指纹图像的特征进行身份识别，其工作流程可以分为下列几个步骤，正确的顺序应该是_____。\n\n（1）指纹图像采集\n\n（2）匹配成功之后，自动进行签到记录并发出"已签到"的提示声音\n\n（3）指纹图像特征值的匹配\n\n（4）指纹图像特征提取','\n',char(10)),'[{"label": "A", "value": "(1)(4)(2)(3)"}, {"label": "B", "value": "(1)(3)(4)(2)"}, {"label": "C", "value": "(1)(2)(4)(3)"}, {"label": "D", "value": "(1)(4)(3)(2)"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(28,28,'CH',replace('下列选项中，体现人工智能技术的有_____。\n\n①使用智能手机中"讯飞语记"应用程序，将演讲者的语音转换为文字\n\n②使用智能手机的微信语音进行通话\n\n③使用Word的自动更正功能自动修正录入的文字\n\n④使用脸部识别技术解锁手机\n\n⑤使用手机扫描二维码订阅公众号','\n',char(10)),'[{"label": "A", "value": "①②④"}, {"label": "B", "value": "①③⑤"}, {"label": "C", "value": "①④"}, {"label": "D", "value": "④⑤"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(29,29,'CH',replace('下列描述或应用中，体现人工智能技术的有_____。\n\n①"百度翻译"可以将输入的中文自动翻译成英文\n\n②一旦有人靠近，酒店大门就会自动打开\n\n③扫地机器人自动规划路线清理房间地面\n\n④校园广播系统一到某时间就自动播放铃声\n\n⑤小王根据同学发布在朋友圈的球鞋照片，通过购物网站"搜图"功能找到了同款球鞋','\n',char(10)),'[{"label": "A", "value": "①②③"}, {"label": "B", "value": "①③⑤"}, {"label": "C", "value": "①④⑤"}, {"label": "D", "value": "②③⑤"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(30,30,'CH','下列关于人工智能技术的说法中错误的是_____。','[{"label": "A", "value": "人工智能是对人脑思维过程的模拟"}, {"label": "B", "value": "具有人工智能的计算机具备了与人完全一样的思维能力"}, {"label": "C", "value": "人工智能技术已经在社会生活的很多方面发挥了积极的作用"}, {"label": "D", "value": "近年来，人工智能技术发展迅速，越来越大众化和人性化"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(31,31,'CH','云计算技术是指_____。','[{"label": "A", "value": "利用计算机对文本、图像、声音、动画、视频等多种媒体信息进行采集、存储、加工和集成的技术"}, {"label": "B", "value": "通过网状的大量客户端获取互联网中木马、病毒的最新信息，推送服务器端进行自动分析和处理后，再把解决方案分发到每一个客户端"}, {"label": "C", "value": "通过分布处理和并行处理的方式，将计算资源放置在网络中，供多个终端共同分享使用"}, {"label": "D", "value": "把任何物品与互联网连接起来，通过信息交换和通讯对物品实现智能化的识别、定位跟踪、监控和管理"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(32,32,'CH','某种智能空调具有网络互连功能，用户将微信账号与空调设备绑定，通过网络在智能手机等终端可查看空调的使用状态、环境数据状况等，还可以在手机端控制空调。这采用的技术是_____。','[{"label": "A", "value": "虚拟实现技术"}, {"label": "B", "value": "物联网技术"}, {"label": "C", "value": "云计算技术"}, {"label": "D", "value": "多媒体技术"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(33,33,'CH','扫地机器人能对周围环境进行探测辨别，自动躲避障碍物，这主要应用了信息技术中的_____。','[{"label": "A", "value": "微电子技术"}, {"label": "B", "value": "计算机技术"}, {"label": "C", "value": "通信技术"}, {"label": "D", "value": "传感技术"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(34,34,'CH','当前，信息技术的发展出现了网络互联的移动化和泛在化趋势，5G网络是第五代移动通信网络，其理论传输速度峰值可达每8秒1GB，比4G网络的传输速度快十倍以上。下列关于5G技术的说法错误的是_____。','[{"label": "A", "value": "随着5G技术的发展，人类进入了万物互联的时代"}, {"label": "B", "value": "5G技术可以为虚拟现实、自动驾驶等提供很好的支撑"}, {"label": "C", "value": "5G技术最主要是提高了网络传输速度，和人工智能、物联网等技术无关"}, {"label": "D", "value": "5G技术有助于推动智慧城市、智慧校园的建设和发展"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(35,35,'CH','下列有关信息技术的说法，错误的是_____。','[{"label": "A", "value": "信息技术是伴随着计算机和互联网技术的发展而诞生的"}, {"label": "B", "value": "信息技术是指获取、表示、传输、存储和加工信息的各种技术总和"}, {"label": "C", "value": "信息技术包含微电子技术、通信技术、计算机技术和传感技术等"}, {"label": "D", "value": "物联网、人工智能、云计算等技术都是当前信息技术发展的热点"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(36,36,'CH','下列不属于信息技术发展趋势的是_____。','[{"label": "A", "value": "人机界面友好"}, {"label": "B", "value": "功能设计个性化"}, {"label": "C", "value": "性能价格比低"}, {"label": "D", "value": "操作步骤简单"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(37,37,'CH','很多城市推出了"手机公交"app，可以在线查询公交车运行的即时信息，极大地方便了市民出行。"手机公交"功能的呈现主要运用的技术是_____。','[{"label": "A", "value": "遥感和地理信息系统"}, {"label": "B", "value": "遥感和全球定位系统"}, {"label": "C", "value": "地理信息系统和数字地球"}, {"label": "D", "value": "全球定位系统和地理信息系统"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(38,38,'CH','互联网给生活方式带来了极大的便捷，人们应用"大众点评"等手机app，可以快速查询到附近各类商业网点的相关信息。该主要运用的技术是_____。','[{"label": "A", "value": "遥感和地理信息系统"}, {"label": "B", "value": "遥感和全球定位系统"}, {"label": "C", "value": "地理信息系统和数字地球"}, {"label": "D", "value": "全球定位系统和地理信息系统"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(39,39,'CH','下列系统中，不属于信息系统的是_____。','[{"label": "A", "value": "地理信息系统"}, {"label": "B", "value": "Windows系统"}, {"label": "C", "value": "中国铁路客户服务系统（12306系统）"}, {"label": "D", "value": "北斗导航系统"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(40,40,'CH','电子邮件系统中，邮件服务器之间发送邮件时采用的协议名称是_____。','[{"label": "A", "value": "URL"}, {"label": "B", "value": "SMTP"}, {"label": "C", "value": "HTTP"}, {"label": "D", "value": "POPv3"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(41,41,'CH','在信息系统开发过程中，第一个阶段是_____。','[{"label": "A", "value": "系统维护"}, {"label": "B", "value": "系统实施"}, {"label": "C", "value": "系统设计"}, {"label": "D", "value": "系统分析"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(42,42,'CH','下列不属于信息系统关键要素的是_____。','[{"label": "A", "value": "人"}, {"label": "B", "value": "信息技术"}, {"label": "C", "value": "数据"}, {"label": "D", "value": "虚拟现实"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(43,43,'CH','在计算机网络中，为了保护内网资源不受外部侵害，可在内部网络与外部网络之间安装一种设备，既阻止外部对内部资源的非法访问，也阻止内部资源非法地向外传送，这种网络连接设备是_____。','[{"label": "A", "value": "路由器"}, {"label": "B", "value": "防火墙"}, {"label": "C", "value": "服务器"}, {"label": "D", "value": "网卡"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(44,44,'CH','在使用电脑过程中，下列不属于网络安全防范措施的是_____。','[{"label": "A", "value": "安装防火墙和防病毒软件，并经常升级"}, {"label": "B", "value": "经常给系统打补丁，堵塞软件漏洞"}, {"label": "C", "value": "不打开陌生人传送过来的不明文件和网址链接"}, {"label": "D", "value": "经常清理电脑中不常用软件和文件"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(45,45,'CH','家庭用的无线路由器通常需要设置网络连接密码，主要是为了_____。','[{"label": "A", "value": "身份验证"}, {"label": "B", "value": "防病毒"}, {"label": "C", "value": "防木马"}, {"label": "D", "value": "加密传输"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(46,46,'CH',replace('对于计算机病毒，我们可以从预防、检查和杀毒三个方面着手，下列属于积极预防措施的是_____。\n\n①对重要数据进行定期备份\n\n②发现计算机不能正常运行后及时查杀病毒\n\n③对下载的共享软件要在查杀病毒后使用\n\n④将操作系统设置为自动更新，及时安装补丁程序，堵住系统漏洞','\n',char(10)),'[{"label": "A", "value": "①②③"}, {"label": "B", "value": "②③④"}, {"label": "C", "value": "①②④"}, {"label": "D", "value": "①②③④"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(47,47,'CH','关于信息安全与网络道德，下列做法正确的是_____。','[{"label": "A", "value": "谨慎使用公共Wi-Fi进行网络购物与支付等操作"}, {"label": "B", "value": "二维码随处可见，都可以放心扫描"}, {"label": "C", "value": "人们可以随时抓拍路人行为，并将其清晰肖像的视频上传到网上"}, {"label": "D", "value": "可以任意评论并转发微博中的各类信息"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(48,48,'CH','从信息安全角度看，以下选项中安全性相对较高、比较适合作为密码的是_____。','[{"label": "A", "value": "MSN5/APP#8"}, {"label": "B", "value": "20041006"}, {"label": "C", "value": "13869998866"}, {"label": "D", "value": "ABCDEF"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(49,49,'CH','以下使用Wi-Fi的做法中，错误的是_____。','[{"label": "A", "value": "使用公共Wi-Fi时，尽量不要使用网络支付软件"}, {"label": "B", "value": "要慎重使用没有密码的陌生Wi-Fi"}, {"label": "C", "value": "为了节约手机流量，可以使用\"蹭网\"软件破解Wi-Fi密码"}, {"label": "D", "value": "尽量选择可靠机构提供的、有验证机制的Wi-Fi"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(50,50,'CH','以下关于在网络空间中交流的说法，错误的是_____。','[{"label": "A", "value": "不随意在网站中公开自己和同学的姓名、学校、住址等信息"}, {"label": "B", "value": "未经当事人允许，不公开与朋友微信聊天的截屏"}, {"label": "C", "value": "不制作、转发丑化同学形象的图片"}, {"label": "D", "value": "给网友提供辱骂他的人的姓名、地址等信息"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(51,51,'CH','下列同学的行为不违背信息道德的是_____。','[{"label": "A", "value": "小王利用自己的计算机专业技能，经常通过网络随意进入别人的计算机，只是浏览文件，不做任何删除和破坏操作"}, {"label": "B", "value": "应朋友的强烈要求，小丽将学校的学籍信息拷贝给他"}, {"label": "C", "value": "小吴将自己为主创作、小组共同完成的创客作品独立署名，参加市级青少年创客大赛评比，获得二等奖"}, {"label": "D", "value": "小木是个摄影高手，他经常登陆某网络社区，上传自己拍摄的风景图片，并标价展示，希望网友对他的作品打赏"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(52,52,'CH','为防止意外情况导致数据丢失，重要数据要及时进行_____。','[{"label": "A", "value": "格式化"}, {"label": "B", "value": "备份"}, {"label": "C", "value": "加密"}, {"label": "D", "value": "杀毒"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(53,53,'CH','网络信息系统中，验证用户身份通常会用到账号密码识别、指纹识别、面部识别、虹膜识别等多种方式。下列说法正确的是_____。','[{"label": "A", "value": "使用多种鉴别方式比单一的鉴别方式相对安全"}, {"label": "B", "value": "面部识别依靠每个人的脸型作为鉴别依据，面部识别无法伪造"}, {"label": "C", "value": "指纹识别相对传统的密码识别更加安全"}, {"label": "D", "value": "为了防止密码被遗忘，最好用生日、手机号等简单数字作为密码"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(54,54,'CH','在使用电脑的过程中，下列不属于网络安全防范措施的是_____。','[{"label": "A", "value": "安装实时监控的杀毒软件，定期更新病毒库"}, {"label": "B", "value": "及时安装补丁程序，修复系统漏洞"}, {"label": "C", "value": "不随意扫描陌生人发送的二维码，不随意点击他人发送的网页链接"}, {"label": "D", "value": "经常清理电脑中不常用软件和文件"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(55,55,'CH','信息时代数据的重要性不言而喻，如何保证数据的安全就显得十分重要了，下列对于数据安全的说法不正确的是_____。','[{"label": "A", "value": "为了便于日后使用，可将身份证正反面的照片发送到微信中保存"}, {"label": "B", "value": "为防止不可抗的自然灾害也会对本地数据安全造成危害，重要数据一般要实行异地备份"}, {"label": "C", "value": "在备份数据前，可对需备份的数据进行无损压缩并加密"}, {"label": "D", "value": "对重要的数据进行备份时，可将数据加密后，上传至第三方网络云盘，尽可能存储在不同网盘中"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(56,56,'CH','为了保障个人电脑上的数据安全，以下做法不恰当的是_____。','[{"label": "A", "value": "安装杀毒软件与防火墙并及时更新"}, {"label": "B", "value": "在网上发送重要数据前先对数据文件加密处理"}, {"label": "C", "value": "定期对电脑上的重要数据文件备份"}, {"label": "D", "value": "将操作系统、应用系统和网站等系统的用户密码信息存储在第三方网络云盘中"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(57,57,'CH','某同学需要发送自己身份证和银行卡的照片给自己的母亲，下列做法中最安全的是_____。','[{"label": "A", "value": "把照片存储在云盘，然后通过微信告知云盘的用户名和密码"}, {"label": "B", "value": "利用电子邮件进行传输，对方收到后立即删除邮件"}, {"label": "C", "value": "利用微信把照片发给母亲，对方收到后立即删除发送的信息"}, {"label": "D", "value": "对照片进行加密压缩后用电子邮件传输，通过电话告知密码"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(58,58,'CH','下列不属于网络防火墙的主要功能是_____。','[{"label": "A", "value": "管理进出网络的访问行为"}, {"label": "B", "value": "对网络病毒进行扫描与拦截"}, {"label": "C", "value": "对网络信息系统的数据进行加密处理"}, {"label": "D", "value": "对网络攻击进行入侵检测并显示警告信息"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(59,59,'CH','下列关于数据加密和解密的说法中错误的是_____。','[{"label": "A", "value": "数据加密是通过加密算法和加密密钥将明文转变为密文"}, {"label": "B", "value": "数据解密是通过解密算法和解密密钥将密文恢复为明文"}, {"label": "C", "value": "数据加密是为了保护密文数据在传输过程中不被非法窃取"}, {"label": "D", "value": "加密密钥和解密密钥不能相同"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(60,60,'CH','有一种数据压缩的编码规则：（1）如果是2～9个连续相同的字符，则用两个字符编码，第一个字符表示相同字符的个数，第二个字符表示该相同字符，如"AAAAA"表示为"5A"；（2）如果一串字符中没有连续相同的字符，就表示成：以数字1开始，后面跟着这一字符串，再以数字1结尾，如字符串"BCE"表示成"1BCE1"。根据这一规则，字符串"XXXXXXXXABCYYYZ"的压缩结果是"8X1ABC13Y1Z1"。那么关于字符串"XXXXXAXAAA"，压缩结果应该是_____。','[{"label": "A", "value": "5X1AX13A"}, {"label": "B", "value": "5X1A11X13A"}, {"label": "C", "value": "5X3A1AXA"}, {"label": "D", "value": "5X3A1A11X1"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(61,61,'CH','有一种利用打孔透光原理设计的简易身份识别卡，每张卡在规定位置上有一排预打孔位，读卡器根据透光检测判断哪些孔位已打孔，哪些未打孔，从而识别出卡的编码。如果要设计一种供全校师生2000人使用的身份卡，则卡上的预打孔位至少需要_____。','[{"label": "A", "value": "10个"}, {"label": "B", "value": "11个"}, {"label": "C", "value": "12个"}, {"label": "D", "value": "20个"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(62,62,'CH','某军舰上有5盏信号灯，信号灯只有"开"和"关"两种状态，如果包括5盏信号灯全关的状态，则最多能表示的信号编码数为_____。','[{"label": "A", "value": "10种"}, {"label": "B", "value": "20种"}, {"label": "C", "value": "32种"}, {"label": "D", "value": "5种"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(63,63,'CH','若在二进制整数11100的右边去掉一个0形成一个新的数，则新的数值是原数值的_____。','[{"label": "A", "value": "1/8"}, {"label": "B", "value": "1/2"}, {"label": "C", "value": "1/4"}, {"label": "D", "value": "1/10"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(64,64,'CH','已知某进制数的等式"37+33=72"，则"72"转换成十进制后应为_____。','[{"label": "A", "value": "110"}, {"label": "B", "value": "114"}, {"label": "C", "value": "58"}, {"label": "D", "value": "63"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(65,65,'CH','下列数据中，有可能是八进制数的是_____。','[{"label": "A", "value": "677"}, {"label": "B", "value": "408"}, {"label": "C", "value": "659"}, {"label": "D", "value": "802"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(66,66,'CH','十进制数14转换成二进制数是_____。','[{"label": "A", "value": "1100"}, {"label": "B", "value": "1101"}, {"label": "C", "value": "1110"}, {"label": "D", "value": "1111"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(67,67,'CH','一幅400×600像素的黑白两色图像与一幅同样像素的16色彩色图像相比，需要的储存空间_____。','[{"label": "A", "value": "前者肯定大于后者"}, {"label": "B", "value": "完全相同"}, {"label": "C", "value": "后者肯定大于前者"}, {"label": "D", "value": "无法判定其大小关系"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(68,68,'CH','将一幅BMP格式的图像转换成JPG格式之后，会使_____。','[{"label": "A", "value": "图像更清晰"}, {"label": "B", "value": "文件容量变大"}, {"label": "C", "value": "文件容量变小"}, {"label": "D", "value": "文件容量大小不变"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(69,69,'CH','在下列对某音频文件进行的编辑中，不影响其存储容量的操作是_____。','[{"label": "A", "value": "采样频率从44.1kHz改为11kHz"}, {"label": "B", "value": "高音量改为低音量"}, {"label": "C", "value": "量化位数从16位改为8位"}, {"label": "D", "value": "双声道改为单声道"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(70,70,'CH','现有两幅未经压缩的BMP格式的位图文件，像素均为1024×768，甲图为16色，乙图为256色，则甲图和乙图的文件大小之比约为_____。','[{"label": "A", "value": "1:16"}, {"label": "B", "value": "1:8"}, {"label": "C", "value": "1:4"}, {"label": "D", "value": "1:2"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(71,71,'CH','将模拟信号数字化，一般经过_____、量化和编码等几个过程。','[{"label": "A", "value": "编程"}, {"label": "B", "value": "采样"}, {"label": "C", "value": "解码"}, {"label": "D", "value": "数制转换"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(72,72,'CH','录制一段时长20秒，采样频率为44.1kHz、量化位数8位的双声道WAV格式音频，其文件大小约为_____。','[{"label": "A", "value": "3.4MB"}, {"label": "B", "value": "1.7MB"}, {"label": "C", "value": "6.8MB"}, {"label": "D", "value": "340KB"}]','TianJin',2025,'');
INSERT INTO questions VALUES(73,73,'CH','智能运动手环的应用开发，体现了哪种数据采集技术的应用_____。','[{"label": "A", "value": "统计报表"}, {"label": "B", "value": "网络爬虫"}, {"label": "C", "value": "API接口"}, {"label": "D", "value": "传感器"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(74,74,'CH','智能手机中内置了多种传感器，可以采集不同数据实现不同功能。用于监测手机发热情况的传感器是_____。','[{"label": "A", "value": "湿度传感器"}, {"label": "B", "value": "温度传感器"}, {"label": "C", "value": "红外传感器"}, {"label": "D", "value": "光线传感器"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(75,75,'CH','研究者通过在线问卷获得数据的过程属于_____。','[{"label": "A", "value": "数据分析"}, {"label": "B", "value": "数据采集"}, {"label": "C", "value": "数据整理"}, {"label": "D", "value": "数据挖掘"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(76,76,'CH','小明同学编写网络爬虫程序，获取到大量有关高考选考科目的数据资料。他的这一操作属于数据处理过程中的_____。','[{"label": "A", "value": "数据分析"}, {"label": "B", "value": "数据整理"}, {"label": "C", "value": "数据采集"}, {"label": "D", "value": "数据加工"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(77,77,'CH','智能手机能够根据光照强度自动调整屏幕亮度，实现这一功能用到的传感器是_____。','[{"label": "A", "value": "重力传感器"}, {"label": "B", "value": "温度传感器"}, {"label": "C", "value": "红外传感器"}, {"label": "D", "value": "光线传感器"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(78,78,'CH','数据处理被广泛应用于日常生活和社会生产的各个领域。数据处理的一般流程为_____。','[{"label": "A", "value": "数据采集→数据分析→数据呈现→数据整理"}, {"label": "B", "value": "数据采集→数据分析→数据整理→数据呈现"}, {"label": "C", "value": "数据采集→数据整理→数据分析→数据呈现"}, {"label": "D", "value": "数据采集→数据呈现→数据分析→数据整理"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(79,79,'CH','小明同学在用电子表格软件进行数据处理时，发现某列单元格中的数值显示为"####"，这表示_____。','[{"label": "A", "value": "公式错误"}, {"label": "B", "value": "格式错误"}, {"label": "C", "value": "列宽不够"}, {"label": "D", "value": "行高不够"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(80,80,'CH','以下关于数据整理的说法，错误的是_____。','[{"label": "A", "value": "数据整理采用的方法有去重、补漏和勘误等"}, {"label": "B", "value": "数据整理的目的是将采集的\"脏数据\"进行校验和标准化"}, {"label": "C", "value": "对现有的数据，只能通过现成的软件或平台进行整理，不能编写程序实现"}, {"label": "D", "value": "数据整理后必须要确保数据的完整性、统一性和准确性，以保证后续用于分析的数据质量"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(81,81,'CH','小明同学在用电子表格软件进行数据处理时，若只想显示出单元格区域中符合条件的若干数据，最适合采用的操作是_____。','[{"label": "A", "value": "排序"}, {"label": "B", "value": "有效性"}, {"label": "C", "value": "筛选"}, {"label": "D", "value": "条件格式"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(82,82,'CH','某电商销售数据报告中有"XX电子产品11月份销售3620台，比上月增长了15.8%"的描述，此处用到的数据分析法是_____。','[{"label": "A", "value": "平均分析法"}, {"label": "B", "value": "量化分析法"}, {"label": "C", "value": "结构分析法"}, {"label": "D", "value": "对比分析法"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(83,83,'CH','小明同学将采集到的水文资料数据进行纠错处理，并将全部有效数据都设置为两位小数的数据格式。小明对数据进行的这一处理过程属于_____。','[{"label": "A", "value": "数据整理"}, {"label": "B", "value": "数据分析"}, {"label": "C", "value": "数据报告"}, {"label": "D", "value": "数据可视化"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(84,84,'CH','下列有关数据分析的说法错误的是_____。','[{"label": "A", "value": "数据分析是用恰当的计算方法与工具对收集的数据进行处理。因此，我们只能对数值型数据进行统计分析"}, {"label": "B", "value": "人们选择哪种数据分析方法，需要根据具体问题而定"}, {"label": "C", "value": "数据分析可以依靠人工方式完成，也可以通过电子表格软件、在线数据分析平台或编写程序完成"}, {"label": "D", "value": "我们可以通过数据分析，提炼出有价值、有意义的数据，以指导决策"}]','TianJin',2025,'A');
