INSERT INTO questions VALUES(101,102,'CH',replace('某球队计算球员平均年龄的部分算法流程图如图所示，其中c用来存储已输入球员年龄的人数，sum用来存储球员年龄之和，d用来存储待输入的球员年龄值。若d为0，表示输入结束。请问图中空白处理框①和②处应填入的是_____。\n\n![](media/image11.jpeg){width="4.689583333333333in"\nheight="3.2916666666666665in"}','\n',char(10)),'[{"label": "A", "value": "①sum←sum+d，②c←c+1"}, {"label": "B", "value": "①sum←sum+c，②c←c+1"}, {"label": "C", "value": "①sum←sum+d，②d←d+1"}, {"label": "D", "value": "①sum←sum+c，②d←d+1"}]','TianJin',2025,'A');
