INSERT INTO questions VALUES(128,129,'CH','用IE浏览器上网时，输入域名www.baidu.com无法访问百度网站，而输入IP地址202.108.22.5则可以正常浏览网页。检查TCP/IP协议的配置，导致此问题的原因最有可能是_____配置错误。','[{"label": "A", "value": "DNS"}, {"label": "B", "value": "IP地址"}, {"label": "C", "value": "子网掩码"}, {"label": "D", "value": "默认网关"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(129,130,'CH','网络管理员写给数学老师的一张带有IP地址的纸条："您的计算机的IP地址是10.33.55.2?6"，其中"?"位置的数字模模糊糊，那么你认为"?"位置的数字不可能是_____。','[{"label": "A", "value": "2"}, {"label": "B", "value": "3"}, {"label": "C", "value": "4"}, {"label": "D", "value": "5"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(130,131,'CH','新来的员工小明让公司的网络管理员给他的电脑分配一个IP地址以便上网，网管给他写了一个IP地址：192.168.1.?72，其中"?"位置的数字模模糊糊，那么你认为"?"位置的数字应该是_____。B','[{"label": "A", "value": "0"}, {"label": "B", "value": "1"}, {"label": "C", "value": "2"}, {"label": "D", "value": "3"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(131,132,'CH','小明为了让家里的几台电脑能同时上网，购买了一台家用路由器。阅读说明书后，知道该路由器的IP地址为：192.168.1.1，说明书中还规定，该IP地址中前三个十进制数表示网络地址，最后一个表示主机地址。根据这样的规则，小明可以把家中一台电脑的IP地址设置为_____。','[{"label": "A", "value": "192.168.1.1"}, {"label": "B", "value": "192.168.1.10"}, {"label": "C", "value": "192.168.1.255"}, {"label": "D", "value": "192.168.2.1"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(132,133,'CH','小明家的网络带宽是100Mbps，如果要将一个125MB的英语学习视频文件下载到本地硬盘上，需要的最少时间是_____。','[{"label": "A", "value": "1.25秒"}, {"label": "B", "value": "10秒"}, {"label": "C", "value": "25秒"}, {"label": "D", "value": "50秒"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(133,134,'CH',replace('小明需要对下图中的花朵进行抠图，但他只有文字处理软件，则需要用到的功能是_____。\n\n![360截图20240701145847694](media/image17.jpeg){width="4.65625in"\nheight="1.2708333333333333in"}','\n',char(10)),'[{"label": "A", "value": "消除背景和裁剪"}, {"label": "B", "value": "裁剪和图片压缩"}, {"label": "C", "value": "消除背景和图片压缩"}, {"label": "D", "value": "重新着色和裁剪"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(134,135,'CH','小明和6位同学组成一个学习小组，要利用暑期时间共同完成一项实践调研任务。他们各自收集和整理了相关资料，为了便于共享较大文件、即时交流讨论，比较适合采用的方式是_____。','[{"label": "A", "value": "用电子邮件每天互相发送收集到的文件资料"}, {"label": "B", "value": "建立一个QQ群交流，文件资料通过群文件共享"}, {"label": "C", "value": "申请一个网盘，建立一个工作文件夹，大家把各自收集到的资料都传到该文件夹下"}, {"label": "D", "value": "建立一个微信群交流，各自把收集到的文件资料发到群里"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(135,136,'CH','小明想要在网上搜索2024年的天津市高考方案，他使用下列关键词进行搜索，其中最有效的是_____。','[{"label": "A", "value": "2024年 天津市"}, {"label": "B", "value": "2024年 天津市 高考试卷"}, {"label": "C", "value": "天津市 高考方案"}, {"label": "D", "value": "2024年 天津市 高考方案"}]','TianJin',2025,'D');
