INSERT INTO questions VALUES(140,141,'CH','随着信息技术的普及，我们可以借助各种数字化资源进行个性化学习和开展研究，以下不属于数字化学习方式的是_____。','[{"label": "A", "value": "观看教师制作的微课"}, {"label": "B", "value": "通过QQ群进行在线讨论"}, {"label": "C", "value": "阅读教师印发的学案"}, {"label": "D", "value": "浏览相关主题研究的网页"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(141,142,'CH','下列关于思维导图的说法中错误的是_____。','[{"label": "A", "value": "思维导图是一个简单、有效的知识管理工具"}, {"label": "B", "value": "思维导图可以帮助进行发散性、结构化思考"}, {"label": "C", "value": "思维导图可以图文并茂地展示思考内容"}, {"label": "D", "value": "思维导图可以有两个中心主题"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(142,143,'CH','思维导图是一个简单、有效的工具，可以帮助我们整理思路、构建知识，绘制的步骤通常为_____。','[{"label": "A", "value": "采用图形修饰-画出主要分支-确定中心主题-选择关键词"}, {"label": "B", "value": "选择关键词-确定中心主题-画出主要分支-采用图形修饰"}, {"label": "C", "value": "确定中心主题-画出主要分支-选择关键词-采用图形修饰"}, {"label": "D", "value": "确定中心主题-采用图形修饰-选择关键词-画出主要分支"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(143,144,'CH','绘制思维导图的工具有很多，以下哪个选项不是思维导图绘制工具_____。','[{"label": "A", "value": "Windows记事本"}, {"label": "B", "value": "Xmind"}, {"label": "C", "value": "百度脑图"}, {"label": "D", "value": "Freemind"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(144,145,'CH','张明小组围绕"智能交通灯"开展编程项目研究，模拟实现对马路上交通灯的科学管控。该项目实施的一般步骤为_____。','[{"label": "A", "value": "分析问题-设计方案-编程调试-交流展示"}, {"label": "B", "value": "设计方案-分析问题-编程调试-交流展示"}, {"label": "C", "value": "设计方案-编程调试-分析问题-交流展示"}, {"label": "D", "value": "分析问题-编程调试-设计方案-交流展示"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(145,146,'CH','李明小组围绕"本地区水污染防治"项目活动共同开展研究，以下操作不便于小组成员间进行项目交流与合作的方式是_____。','[{"label": "A", "value": "小组成员通过QQ群及时交流研究思路和想法"}, {"label": "B", "value": "小组成员独立完成项目研究后，再由李明同学整理汇总"}, {"label": "C", "value": "小组成员使用在线文档编辑工具协同写作，完成研究报告"}, {"label": "D", "value": "小组成员通过云存储方式分享各自研究过程中的文档材料"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(146,147,'CH','以下有关数字化学习的说法，错误的是_____。','[{"label": "A", "value": "数字化学习资源与以往传统资源相比较，最大优势在于其中的资源被存储在数字设备中，安全性较高"}, {"label": "B", "value": "数字化学习资源形式多样，可以包含文本、图像、声音、视频等多种媒体"}, {"label": "C", "value": "数字化学习资源越来越为大众所接受，能有效支持个性化学习和终身学习"}, {"label": "D", "value": "人们通过互联网访问数字图书馆网站，可以在任何时间、任何地点方便快捷地享用数字化信息资源"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(147,148,'CH','下面关于人工智能及其所包含内容的描述，正确的是_____。','[{"label": "A", "value": "人工智能就是机器学习"}, {"label": "B", "value": "深度学习是一种机器学习的方法"}, {"label": "C", "value": "人工智能就是深度学习"}, {"label": "D", "value": "机器学习就是深度学习"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(148,149,'CH','关于机器学习，下列描述正确的是_____。','[{"label": "A", "value": "应用机器学习算法对计算机中存储的历史数据进行处理，这个过程称为预测"}, {"label": "B", "value": "应用机器学习算法对计算机中存储的历史数据进行处理，这个过程称为训练"}, {"label": "C", "value": "预测和模型在机器学习中发挥重要作用，预测产生模型，模型指导预测"}, {"label": "D", "value": "机器学习的模型是事先在程序中定制的，不会改变"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(149,150,'CH','要想让机器具有智能，必须让机器具有知识。因此，在人工智能中有一个研究领域，主要研究计算机如何获取知识和技能，实现自我完善，这个研究领域叫_____。','[{"label": "A", "value": "专家系统"}, {"label": "B", "value": "机器学习"}, {"label": "C", "value": "人机交互"}, {"label": "D", "value": "模式识别"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(150,151,'CH','下列有关数据的说法，错误的是_____。','[{"label": "A", "value": "用计算机处理数据可以获得较高的效率"}, {"label": "B", "value": "计算机可以处理的数据必须是数字"}, {"label": "C", "value": "人们在使用数据的同时，自身的行为也在产生数据"}, {"label": "D", "value": "数据就在我们身边，它是客观存在的"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(151,152,'CH','乘坐公共交通工具时，人们需要出示"健康码"显示自己的健康状态，下列说法错误的是_____。','[{"label": "A", "value": "\"健康码\"是一种人们健康状态相关数据的呈现形式"}, {"label": "B", "value": "人们健康状态的相关数据也可以用其他形式的数据呈现"}, {"label": "C", "value": "健康状态的相关数据是客观存在的，\"健康码\"一旦生成不会改变"}, {"label": "D", "value": "技术的发展丰富了人们健康状态相关数据的呈现方式，提高了数据处理能力"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(152,153,'CH','当你收到陌生人发来的短信时，根据信息的特征，最应关注的是信息的_____。','[{"label": "A", "value": "共享性"}, {"label": "B", "value": "时效性"}, {"label": "C", "value": "价值性"}, {"label": "D", "value": "真伪性"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(153,154,'CH','小明在"人人通"学习平台上发现一门人工智能的课程，他将课程邀请码发送给同学，邀请同学一起学习。这最能体现信息的_____。','[{"label": "A", "value": "时效性"}, {"label": "B", "value": "共享性"}, {"label": "C", "value": "价值性"}, {"label": "D", "value": "存储性"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(154,155,'CH','下列关于数据和信息的说法正确的是_____。','[{"label": "A", "value": "数据是信息的载体，数据是信息所表示的意义"}, {"label": "B", "value": "数据是信息的载体，信息是数据所表示的意义"}, {"label": "C", "value": "信息是数据的载体，数据是信息所表示的意义"}, {"label": "D", "value": "信息是数据的载体，信息是数据所表示的意义"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(155,156,'CH','"割圆术"是求圆周率的一种算法。我国古代数学家刘徽发现当圆内接正多边形的边数无限增加时，其形状就越接近于圆。他利用割圆术计算出圆周率的近似值为3.14，并以此来计算圆的面积。下列有关该事例中数据、信息、知识、智慧的说法，错误的是_____。','[{"label": "A", "value": "刘徽从正六边形开始，逐次倍增边数，最后将圆周率计算到3.1416，其中\"3.1416\"是数据"}, {"label": "B", "value": "祖冲之继承并发展了\"割圆术\"，将圆周率计算到3.1415926与3.1415927之间，这体现了信息的真伪性"}, {"label": "C", "value": "刘徽采用割圆术这一方法，是智慧的体现"}, {"label": "D", "value": "用3.14乘以半径的平方可以得到圆面积的近似值，这是知识"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(156,157,'CH','下列选项中未用到大数据技术的是_____。','[{"label": "A", "value": "某平台以网民行为数据为基础，研究关键词搜索趋势，洞察网民消费特征"}, {"label": "B", "value": "在超市、银行等场所，用手持测温仪测量入场人员的体温数据"}, {"label": "C", "value": "某网站利用可视化\"迁徙\"地图，分析各城市人口流动轨迹与特征"}, {"label": "D", "value": "某景区利用\"客流分析系统\"分析游客密度、景点人流趋势等，确保景区有序的活动和良好的交通秩序"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(157,158,'CH','电商平台利用大数据技术给用户个性化推荐商品，不需要考虑的因素是_____。','[{"label": "A", "value": "该用户浏览过什么商品"}, {"label": "B", "value": "该用户的消费能力"}, {"label": "C", "value": "该用户购买过什么商品"}, {"label": "D", "value": "该用户为什么购买这件商品"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(158,159,'CH','生物特征识别技术是在图像识别的基础上发展起来的，不能用于生物特征识别的是_____。D','[{"label": "A", "value": "指纹"}, {"label": "B", "value": "虹膜"}, {"label": "C", "value": "人脸"}, {"label": "D", "value": "体重"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(159,160,'CH','下面关于人工智能技术的说法中错误的是_____。','[{"label": "A", "value": "人工智能一定程度上能模仿人类的活动"}, {"label": "B", "value": "人工智能可以全面取代人类活动"}, {"label": "C", "value": "人工智能的发展将改变人类社会生活"}, {"label": "D", "value": "人工智能的发展也会产生一些负面的社会影响"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(160,161,'CH','用手机远程操控家中的空调、窗帘和电热水器，主要运用到的技术是_____。','[{"label": "A", "value": "多媒体技术"}, {"label": "B", "value": "物联网技术"}, {"label": "C", "value": "云计算技术"}, {"label": "D", "value": "虚拟现实技术"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(161,162,'CH','下列应用中，没有用到物联网技术的是_____。','[{"label": "A", "value": "共享单车"}, {"label": "B", "value": "无人驾驶汽车"}, {"label": "C", "value": "手机通信"}, {"label": "D", "value": "智能水表"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(162,163,'CH','信息系统是推动信息社会发展的重要因素之一，在社会生产和人类生活的各个方面得到广泛应用，下面不属于信息系统的是_____。','[{"label": "A", "value": "安卓系统"}, {"label": "B", "value": "校园一卡通系统"}, {"label": "C", "value": "医院挂号系统"}, {"label": "D", "value": "图书管理系统"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(163,164,'CH','人员是信息系统的组成要素之一，下面属于超市信息系统中人员角色的是_____。','[{"label": "A", "value": "超市决策者"}, {"label": "B", "value": "系统的设计开发和维护者"}, {"label": "C", "value": "超市员工和顾客"}, {"label": "D", "value": "以上都是"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(164,165,'CH','在下面的生活场景中，有利于保护个人信息安全的行为是_____。','[{"label": "A", "value": "丢弃火车票、机票前，涂掉或销毁印有个人信息的部分"}, {"label": "B", "value": "对于路边培训机构的推销人员，可以留下自己真实的联系方式，这样可以获得一份小礼物"}, {"label": "C", "value": "扫描陌生人提供的二维码，只要不关注、不支付，就不会有风险"}, {"label": "D", "value": "小明收到一封电子邮件，看到主题中写有自己的网络昵称，他就放心地打开查看"}]','TianJin',2025,'A');
