INSERT INTO questions VALUES(180,181,'CH','在设计"求一元二次方程实数根"的算法中，如果方程不存在实数根，也要求输出"方程无实数根"。这一要求主要体现了算法特征中的_____。','[{"label": "A", "value": "确定性"}, {"label": "B", "value": "有穷性"}, {"label": "C", "value": "有0个或多个输入"}, {"label": "D", "value": "有1个或多个输出"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(181,182,'CH',replace('某算法用伪代码描述如下：\n\n输入两个互不相等的自然数A,B\n\nif A<B then\n\n(A←A+B, B←A-B, A←A-B)\n\n输出A,B\n\n上述算法实现的功能是_____。','\n',char(10)),'[{"label": "A", "value": "交换A、B的值"}, {"label": "B", "value": "比较两个数的大小"}, {"label": "C", "value": "从小到大输出两个自然数"}, {"label": "D", "value": "从大到小输出两个自然数"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(182,183,'CH',replace('一物体做自由落体运动，求物体下落高度h，计算公式为\n（g是重力加速度，t是时间）。求解该问题的步骤包括：\n\n①用公式计算物体下落高度\n\n②输入重力加速度g\n\n③输入时间t\n\n④输出结果h\n\n下列步骤排列顺序正确的是_____。','\n',char(10)),'[{"label": "A", "value": "②③①④"}, {"label": "B", "value": "①③②④"}, {"label": "C", "value": "②①③④"}, {"label": "D", "value": "①②③④"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(183,184,'CH',replace('某旅游景点售卖儿童票的算法流程图如图所示。现有五名儿童，身高分别为：①1.6米②1.2米③1.1米④1.4米⑤1.5米，其中符合购半票的有_____。\n\n![](media/image19.jpeg){width="2.5625in" height="2.2083333333333335in"}','\n',char(10)),'[{"label": "A", "value": "①②③"}, {"label": "B", "value": "②③④"}, {"label": "C", "value": "②④⑤"}, {"label": "D", "value": "①④⑤"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(184,185,'CH',replace('有如下Python程序段：\n\nnames=["张飞","关羽","赵云","刘备"]\n\nname=input(请输入要查找的姓名：)\n\nif len(name)<2:\n\nprint("输入有误，请重新输入！")\n\nelif name in names:\n\nprint("找到此人")\n\nelse:\n\nprint("找不到此人")\n\n若输入赵云赵子龙，程序的输出结果为_____。','\n',char(10)),'[{"label": "A", "value": "输入有误，请重新输入！"}, {"label": "B", "value": "找到此人"}, {"label": "C", "value": "找不到此人"}, {"label": "D", "value": "程序报错"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(185,186,'CH',replace('将10个数据"23,15,51,36,78,47,39,9,88,96"依次存放在列表num中，若编写如下Python程序段，找出其中大于70的数的个数，则划线处应填写的内容为_____。\n\nnums=[23,15,51,36,78,47,39,9,88,96]\n\nn=0\n\nm=70\n\nfor i in range(0,10):\n\nif_____:\n\nn=n+1\n\nprint(大于70的数的个数为：,n)','\n',char(10)),'[{"label": "A", "value": "nums[i]>n"}, {"label": "B", "value": "nums[i]<n"}, {"label": "C", "value": "nums[i]>m"}, {"label": "D", "value": "nums[i]<m"}]','TianJin',2025,'C');
