INSERT INTO questions VALUES(187,188,'CH',replace('体重指数=体重/身高的平方（单位：![360截图20230704111543842](media/image20.jpeg){width="0.6770833333333334in"\nheight="0.33194444444444443in"}\n）。若用变量w表示体重，单位是kg；用h表示身高，单位是cm；则下列计算体重指数的Python表达式正确的是_____。','\n',char(10)),'[{"label": "A", "value": "w//((h//100)**2)"}, {"label": "B", "value": "w/(h/100**2)"}, {"label": "C", "value": "w\\\\(h\\\\100**2)"}, {"label": "D", "value": "w/(h/100)**2"}]','TianJin',2025,'D');
