INSERT INTO questions VALUES(204,205,'CH','人工智能领域里，研究计算机怎样模拟或实现人类的学习行为，以获取新的知识或技能，并重组已有知识结构使之不断改善自身的性能的技术是_____。','[{"label": "A", "value": "机器学习"}, {"label": "B", "value": "语音交互"}, {"label": "C", "value": "图像识别"}, {"label": "D", "value": "自然语言处理"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(205,206,'CH','关于信息技术未来发展方向的说法错误的是_____。','[{"label": "A", "value": "\"互联网+\"保进了信息化和工业化深度融合"}, {"label": "B", "value": "物联网成为数据采集的重要来源"}, {"label": "C", "value": "大数据成为重要的战略资源"}, {"label": "D", "value": "跨领域应用与学科交叉越来越少"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(206,207,'CH','在火车站的自动售/取票终端设备上，当乘客把身份证放在感应区，系统可以自动识别乘客信息，免去了人工录入信息的麻烦。这对信息系统的_____进行了优化。','[{"label": "A", "value": "输出功能"}, {"label": "B", "value": "输入功能"}, {"label": "C", "value": "处理功能"}, {"label": "D", "value": "存储功能"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(207,208,'CH','身份认证是保护信息系统安全的第一道防线，用来防止未授权用户私自访问系统，以下身份认证方式不恰当的是_____。','[{"label": "A", "value": "使用数字证书、支付盾等唯一信物登录"}, {"label": "B", "value": "为了好记，将网络支付账号设置成和微博、邮箱等相同的用户名和密码"}, {"label": "C", "value": "使用人脸、指纹、虹膜等用户生物特征作为登录方式"}, {"label": "D", "value": "为网银账户设置单独的高安全级别的密码"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(208,209,'CH','信息技术在促进社会发展的同时，也带来一系列信息安全和社会责任方面的问题，下列做法正确的是_____。','[{"label": "A", "value": "将随手抓拍的带有他人车辆牌照信息的照片不经处理直接发布到互联网上"}, {"label": "B", "value": "二维码随处可见，可以放心扫描"}, {"label": "C", "value": "引用他人作品时注明出处"}, {"label": "D", "value": "自己的身份证照片随意发送给他人"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(209,210,'CH','图像、音频和视频等类型的信息，经过数字化后生成的数据量较大，包含了许多冗余信息。针对数据压缩，以下说法错误的是_____。','[{"label": "A", "value": "数据压缩的目的是使文件更少地占用存储空间和缩短传输时间"}, {"label": "B", "value": "常用的数据压缩方法分为无损压缩和有损压缩"}, {"label": "C", "value": "MP3是常见的音频数据无损压缩格式"}, {"label": "D", "value": "图像压缩比例越大，文件越小，清晰度越低"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(210,211,'CH',replace('某十字路口有四个车道，每车道用一个指示灯指明通行状态，下表是各指示灯的控制编码及对应的状态。若某一时段只允许车辆左转，但不允许车辆直行和右转，则此时的控制码应该是_____。\n\n![](media/image25.jpeg){width="4.041666666666667in"\nheight="1.1715277777777777in"}','\n',char(10)),'[{"label": "A", "value": "01111111"}, {"label": "B", "value": "11010101"}, {"label": "C", "value": "11101010"}, {"label": "D", "value": "01010101"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(211,212,'CH','图像经过数字化可以转换为不同格式的文件进行保存。以下说法描述错误的是_____。','[{"label": "A", "value": "常见的图像文件格式有JPG/JPEG、PNG和BMP等"}, {"label": "B", "value": "将同一图像分别存储为BMP、JPG/JPEG和PNG格式，BMP文件质量最低，占用存储空间最小"}, {"label": "C", "value": "JPG/JPEG是网络传输常用的图像文件格式"}, {"label": "D", "value": "扫描仪、智能手机和计算机上的摄像头是常用的图像数字化设备"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(212,213,'CH','电子警察通过拍照的方式来约束车辆的行为，该拍照过程属于_____。','[{"label": "A", "value": "数据采集"}, {"label": "B", "value": "数据分析"}, {"label": "C", "value": "数据挖掘"}, {"label": "D", "value": "数据可视化表达"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(213,214,'CH',replace('下图为使用不同无线网络的用户访问某网站的次数统计情况，其中用到的数据分析方法是_____。\n\n![](media/image26.jpeg){width="1.8229166666666667in"\nheight="1.5520833333333333in"}','\n',char(10)),'[{"label": "A", "value": "对比分析法"}, {"label": "B", "value": "平均分析法"}, {"label": "C", "value": "结构分析法"}, {"label": "D", "value": "量化分析法"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(214,215,'CH',replace('某银行国际业务部通过折线图比较业务处理效率情况，以掌握业务效率变化，及时发现问题，提高服务水平。下面是汇入汇款、汇出汇款、电子转发和分报四种业务的折线图。从折线图可以看出，四种业务所耗时间变化波动最小的是_____。\n\n![](media/image27.jpeg){width="4.5625in" height="2.1354166666666665in"}','\n',char(10)),'[{"label": "A", "value": "汇入汇款"}, {"label": "B", "value": "汇出汇款"}, {"label": "C", "value": "电子转发"}, {"label": "D", "value": "分报"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(215,216,'CH',replace('以下是求解两个正整数a和b的最小公倍数的算法描述，划线处应填写的数字是_____。\n\n第1步：输入正整数a和b；\n\n第2步：如果a<b，则交换a,b的值；\n\n第3步：n=1；\n\n第4步：a=a*n；\n\n第5步：如果a不能整除b，则n=n+1，然后跳到第_____步；\n\n第6步：输出结果a。','\n',char(10)),'[{"label": "A", "value": "1"}, {"label": "B", "value": "2"}, {"label": "C", "value": "3"}, {"label": "D", "value": "4"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(216,217,'CH',replace('小明依据所在城市出租车的收费标准，绘制了如下流程图。如果要测试所有分支是否正确，以下测试数据中，最恰当的一组是_____。\n\n![](media/image28.jpeg){width="4.354166666666667in"\nheight="3.470833333333333in"}','\n',char(10)),'[{"label": "A", "value": "2，10，12"}, {"label": "B", "value": "10，2，6"}, {"label": "C", "value": "-1，6，10"}, {"label": "D", "value": "3，11，100"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(217,218,'CH',replace('小明编写了一个Python程序实现微信抢红包功能，程序运行结果如图所示，下面程序段的划线处应填写的内容为_____。\n\nimport random\n\nn=int(input("输入红包总数(个):"))\n\nm=int(input("输入红包金额(元):"))*100-n\n\n#金额以"分"为单位并保证每个人至少抢到一分钱\n\nfor i in range__________:\n\nif i==n:\n\nx=m\n\nelse:\n\nx=random. randint(0,int(m/(n-i+1)*2))\n\nm=m-x\n\nprint("第",i,"个红包金额为:",(x+1)/100,"元")','\n',char(10)),'[{"label": "A", "value": "(1,n+1,1)"}, {"label": "B", "value": "(1,n,1)"}, {"label": "C", "value": "(0,n,1)"}, {"label": "D", "value": "(0,n+1,1)"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(218,219,'CH',replace('小明同学先后给变量a进行如下赋值操作,则变量a最后的值为_____。\n\na=100\n\na=a+1\n\na=\''abc\''','\n',char(10)),'[{"label": "A", "value": "100"}, {"label": "B", "value": "\\''abc\\''"}, {"label": "C", "value": "111"}, {"label": "D", "value": "abc"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(219,220,'CH','以下不属于智能手机操作系统的是_____。D','[{"label": "A", "value": "Harmony"}, {"label": "B", "value": "Android"}, {"label": "C", "value": "iOS"}, {"label": "D", "value": "Mac"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(220,221,'CH','无线路由器是现在最常用的无线网络设备，以下关于无线路由器的描述错误的是_____。','[{"label": "A", "value": "无线路由器的管理密码和连接密码必须是一致的"}, {"label": "B", "value": "路由器可以用于不同网络的互联"}, {"label": "C", "value": "WAN口用于连接外网，LAN口用于连接内网"}, {"label": "D", "value": "路由器可以给接入网络的设备自动分配IP地址"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(221,222,'CH','小明的网课学习时间临近，家中的宽带突然发生故障，此时可以将移动通信网络共享给其他设备使用。这种方式称为_____。','[{"label": "A", "value": "设置无线热点"}, {"label": "B", "value": "设置无线密码"}, {"label": "C", "value": "设置有线热点"}, {"label": "D", "value": "设置有线密码"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(222,223,'CH','关于搜索引擎的说法错误的是_____。','[{"label": "A", "value": "分类目录型搜索引擎查全率高"}, {"label": "B", "value": "关键词（全文）搜索引擎查准率高"}, {"label": "C", "value": "搜索引擎只能对输入的文字进行信息搜索"}, {"label": "D", "value": "元搜索引擎是一种建立在搜索引擎之上的搜索引擎"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(223,224,'CH','下列关于思维导图的说法中错误的是_____。D','[{"label": "A", "value": "思维导图是一个简单、有效的知识管理工具"}, {"label": "B", "value": "思维导图可以帮助我们进行发散性、结构化思考"}, {"label": "C", "value": "我们可以借助XMind、MindMaster、百度脑图等完成思维导图的绘制"}, {"label": "D", "value": "\"确定中心主题→ 选择关键词→ 画出主要分支→ 采用图形修饰\"是正确的思维导图绘制方法"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(224,225,'CH','数据处理要经历数据采集、数据整理、数据分析和数据呈现等环节，以"南水北调"工程中的数据处理为例，借助数字化学习资源可以更好地帮助我们完成数据处理过程，在以下方法中可以实现的是_____。','[{"label": "A", "value": "通过访问权威机构网站（如水利部网站）获取数据"}, {"label": "B", "value": "使用Python语言编写网络爬虫程序快速准确地获取水利部网站中的相关数据"}, {"label": "C", "value": "注册账号并登陆国家统计局网站后， 查找全国供水数据， 完成在线数据分析，最后查看并保存分析结果"}, {"label": "D", "value": "以上都对"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(225,226,'CH','下列选项中关于数据的说法，正确的是_____。','[{"label": "A", "value": "数据是计算机发明以后才有的"}, {"label": "B", "value": "数据是对现实世界客观事物的符号记录"}, {"label": "C", "value": "相同的数据表示相同的信息"}, {"label": "D", "value": "数据只包含数字"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(226,227,'CH',replace('请将以下关于信息的描述按照时效性、共享性、载体依附性、价值相对性依次进行排序，正确的选项是_____。\n\n①教师通过钉钉平台发布课后作业，班级内的同学可以在线完成\n\n②许多古籍用文字记录了我国古代的历史与文化\n\n③股市中的某个股票大跌，既有人买入，也有人卖出\n\n④网络售票系统会及时更新车次和余票信息','\n',char(10)),'[{"label": "A", "value": "④①②③"}, {"label": "B", "value": "②③④①"}, {"label": "C", "value": "①②③④"}, {"label": "D", "value": "①④③②"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(227,228,'CH','学生入校时要通过校门口的红外测温仪进行体温检测，小明通过时测温仪显示36℃，下列关于数据、信息和知识的说法中正确的是_____。','[{"label": "A", "value": "\"36℃\"是信息，所以信息是数据的载体"}, {"label": "B", "value": "数字\"36\"是数据，数据就是数值"}, {"label": "C", "value": "\"人体体温低于37℃时不属于发烧\"是知识"}, {"label": "D", "value": "\"小明的体温是36℃\"是数据"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(228,229,'CH','人们在日常生活中获取数据的同时，也在不断产生数据。下列行为产生的数据属于大数据的是_____。','[{"label": "A", "value": "某校学生每天借阅图书的数据"}, {"label": "B", "value": "个人通讯录中添加的新联系人数据"}, {"label": "C", "value": "某校新生填写学籍信息，由学校汇总后的数据"}, {"label": "D", "value": "电子商务平台上商品买卖产生的交易记录数据"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(229,230,'CH','很多智能手表具有丰富的功能，如语音搜索、定位跟踪、心率监测、智能锻炼、睡眠质量监测等，这些功能实现的基础是_____。','[{"label": "A", "value": "射频识别技术"}, {"label": "B", "value": "传感技术"}, {"label": "C", "value": "虚拟现实技术"}, {"label": "D", "value": "机器学习技术"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(230,231,'CH','在线政府是充分利用信息技术实现社会管理和公共服务的新型政府治理模式，下列不属于在线政府特征的是_____。','[{"label": "A", "value": "权利集中"}, {"label": "B", "value": "公开透明"}, {"label": "C", "value": "科学决策"}, {"label": "D", "value": "高效治理"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(231,232,'CH','中国铁路客户服务中心的订票网站是典型的信息系统。从信息系统组成看，用户账号、支付金额属于_____。','[{"label": "A", "value": "用户"}, {"label": "B", "value": "软件"}, {"label": "C", "value": "硬件"}, {"label": "D", "value": "数据"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(232,233,'CH','很多城市的火车站启用了自助验证、验票系统，旅客可以持身份证，通过人脸识别系统确认后快速进站乘车。这主要采用了信息系统安全风险防范技术中的_____。','[{"label": "A", "value": "数据备份"}, {"label": "B", "value": "身份认证"}, {"label": "C", "value": "数据加密"}, {"label": "D", "value": "设置防火墙"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(233,234,'CH','小明接到自称是某电商平台工作人员的电话，告知他可以点击某个链接领取购物津贴，但需要提供身份证号、银行卡号和密码，下列做法恰当的是_____。','[{"label": "A", "value": "同相关部门咨询情况并向公安机关举报"}, {"label": "B", "value": "按照对方的指示进行操作"}, {"label": "C", "value": "向亲友分享领取津贴的信息"}, {"label": "D", "value": "告知对方相关信息"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(234,235,'CH','数据加密技术可以用来保障信息系统中的数据安全，下列说法错误的是_____。','[{"label": "A", "value": "数据加密技术是通过加密算法和加密密钥将明文变为密文"}, {"label": "B", "value": "数据解密技术是通过解密算法和解密密钥将密文变为明文"}, {"label": "C", "value": "为了确保加密与解密可逆，加密与解密的密钥必须相同"}, {"label": "D", "value": "量子密钥是目前最安全的加密方式"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(235,236,'CH','二进制在我国古代就有很好的运用，例如《易经》中有"太极生两仪，两仪生四象"的说法。如果用二进制数来表示"两仪"和"四象"，那么"四象"可以用_____位二进制数表示。','[{"label": "A", "value": "1"}, {"label": "B", "value": "2"}, {"label": "C", "value": "3"}, {"label": "D", "value": "4"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(236,237,'CH','小明下载了一段10秒的音频文件进行编辑，设置参数为：双声道、采样频率44.1kHz、量化位数16，完成后保存为WAV格式。下列说法错误的是_____。','[{"label": "A", "value": "其他参数不变，增大量化位数，文件的存储容量会变大"}, {"label": "B", "value": "该音频文件的存储容量为44100*16*2*10/8 Byte"}, {"label": "C", "value": "为了尽可能提高音质，可不断提高采样频率"}, {"label": "D", "value": "将WAV文件转成MP3格式是有损压缩"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(237,238,'CH','小明使用Python程序从网上获取共享单车的运营信息，如学校周边区域内当日共享单车的数量、骑行距离等。他所采用的数据获取方法是_____。','[{"label": "A", "value": "查阅文献获取数据"}, {"label": "B", "value": "在线问卷获取数据"}, {"label": "C", "value": "传感器获取数据"}, {"label": "D", "value": "网络爬虫获取数据"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(238,239,'CH','小红发现收集的全国各地区2022年四个季度的年生产总值数据文件存在一些问题，需要进行数据整理。下列做法不合理的是_____。','[{"label": "A", "value": "重复的数据应在进一步审核的基础上进行合并或删除操作"}, {"label": "B", "value": "对格式不一致的数据，需要进行相应转换"}, {"label": "C", "value": "不符合一般规律的异常数据应该直接删除"}, {"label": "D", "value": "缺失的数据通常可采用平均值、中间值或概率统计值来填补"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(239,240,'CH',replace('小明对课文《济南的冬天》中的文本进行数据分析，生成的词云如下图所示。下列有关该词云图的说法错误的是_____。\n\n![360截图20230704111725010](media/image29.jpeg){width="3.76875in"\nheight="2.390972222222222in"}','\n',char(10)),'[{"label": "A", "value": "词云图能帮助我们快速获取到文本数据中所蕴含的关键信息"}, {"label": "B", "value": "从词云图可以分析出文章中词语\"济南\"要比\"天气\"出现的频率高"}, {"label": "C", "value": "词云图是抽取了文章中的关键词并进行可视化地呈现"}, {"label": "D", "value": "词云图中没有显示\"的\"\"地\"\"得\"等词，是因为该文章中没有这些词"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(240,242,'CH',replace('我们要学会用算法的视角看待生活，用算法的思维去解决实际问题。下图是某购物网站给出的购买流程，想一想其中从步骤3到步骤4可以用算法三种基本控制结构中的_____描述。\n\n![](media/image30.jpeg){width="4.911111111111111in"\nheight="1.1236111111111111in"}','\n',char(10)),'[{"label": "A", "value": "顺序结构"}, {"label": "B", "value": "选择结构"}, {"label": "C", "value": "循环结构"}, {"label": "D", "value": "网状结构"}]','TianJin',2025,'');
INSERT INTO questions VALUES(241,243,'CH',replace('要计算并输出"1+4+7+10+\...+25"的结果，用到的Python程序语句有：\n\n①for i in range(1,26,3):\n\n②s=0\n\n③s=s+i\n\n④print(s）\n\n这些程序语句正确的排列顺序是_____。','\n',char(10)),'[{"label": "A", "value": "①②③④"}, {"label": "B", "value": "①③②④"}, {"label": "C", "value": "②①③④"}, {"label": "D", "value": "③①②④"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(242,244,'CH',replace('在信息传递过程中，人们通常会对一些关键信息进行加密。下面是小明编写的实现加密功能的Python程序段，若输入明文为"a587"，则输出密文为_____。\n\n![360截图20230704110048715](media/image31.jpeg){width="4.113888888888889in"\nheight="3.1902777777777778in"}','\n',char(10)),'[{"label": "A", "value": "c907"}, {"label": "B", "value": "c709"}, {"label": "C", "value": "a709"}, {"label": "D", "value": "a907"}]','TianJin',2025,'C');
