INSERT INTO questions VALUES(244,246,'CH','在2022年北京冬残奥会速度滑冰比赛中，为便于采集比赛过程中的数据，运动员都要佩戴一个有RFID电子标签的小芯片，其中RFID是指_____。','[{"label": "A", "value": "传感技术"}, {"label": "B", "value": "红外传输技术"}, {"label": "C", "value": "射频识别技术"}, {"label": "D", "value": "嵌入式系统技术"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(245,247,'CH','小红说自己家里用的是宽带百兆网，小明说他家的网是千兆网。他们所说的百兆网或千兆网，其实是在描述网络带宽。带宽的单位是_____。','[{"label": "A", "value": "MB/s"}, {"label": "B", "value": "KB/s"}, {"label": "C", "value": "B/s"}, {"label": "D", "value": "bit/s"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(246,248,'CH','在数字化学习环境下，学习者可以根据自己的特点自行安排学习进度，从互联网上选择自己需要的资源，按照适合自己的方式进行学习。这体现了数字化学习_____的特点。','[{"label": "A", "value": "个性化"}, {"label": "B", "value": "合作性"}, {"label": "C", "value": "问题化"}, {"label": "D", "value": "创造性和再生性"}]','TianJin',2025,'A');
