INSERT INTO questions VALUES(248,250,'CH','下列关于获取信息的说法，错误的是_____。','[{"label": "A", "value": "收看中央电视台的天气预报节目是一个获取天气信息的好方法"}, {"label": "B", "value": "获取任何信息最快最好的方法就是访问网络"}, {"label": "C", "value": "亲自观察、调查、实验、测量后获取的第一手信息，具有较高的真实性和可信度"}, {"label": "D", "value": "在获取信息时，选择什么信息来源，使用什么获取方法要根据具体情况而定"}]','TianJin',2025,'B');
