INSERT INTO questions VALUES(250,252,'CH','当我们在网上注册账号、登录或修改个人信息时，常常需要我们输入手机验证码，如下图所示。手机验证码为动态生成，超出规定时间就无法使用，需要重新发送新的验证码，这主要体现了信息的_____特征。','[{"label": "A", "value": "传递性"}, {"label": "B", "value": "共享性"}, {"label": "C", "value": "时效性"}, {"label": "D", "value": "载体依附性"}]','TianJin',2025,'C');
