INSERT INTO questions VALUES(252,254,'CH',replace('下列属于大数据应用的是_____。\n\n①通过手机定位获得城市热力图\n\n②体育老师通过电子表格统计所教班级学生体质数据\n\n③电商网站针对客户个人喜好和消费能力推荐不同的商品\n\n④利用导航地图规划出行"捷径"\n\n⑤政府部门开发的"精准扶贫云平台"为扶贫工作保驾护航','\n',char(10)),'[{"label": "A", "value": "①②③"}, {"label": "B", "value": "①②③④"}, {"label": "C", "value": "①③④⑤"}, {"label": "D", "value": "①②④⑤"}]','TianJin',2025,'');
INSERT INTO questions VALUES(253,255,'CH','党的二十大报告提出要加快建设农业强国，到2035年基本实现农业农村现代化的目标。如今，随着人工智能、物联网、大数据、5G等信息技术的发展，我国部分区域已经进入了农业4.0的初探阶段。人工智能技术产生的巨大推动力，促使传统农业发生了巨大变化。下列说法中，错误的是_____。','[{"label": "A", "value": "农场中的智能分拣机可取代一些相对简单重复的人工劳动"}, {"label": "B", "value": "基于机器视觉的病虫害自动监测平台，可以帮助农民科学判断病虫害状况，提出对应的措施和方法"}, {"label": "C", "value": "人工智能技术有助于实现农业精细化管理、节约资源、保障产品安全"}, {"label": "D", "value": "人工智能技术的发展将致使农业知识彻底失去学习的必要"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(254,256,'CH','"云计算"应用能够让许多远程计算机同时分担完成一项任务，例如单台计算机需要100分钟完成的任务，让多台计算机联网共同协作完成，或许只要1分钟时间即可。这种通过网络多台计算机协同完成一项任务的应用，主要体现了计算机网络的_____功能。','[{"label": "A", "value": "分布控制与分布处理"}, {"label": "B", "value": "资源共享"}, {"label": "C", "value": "数据通信"}, {"label": "D", "value": "信息传输"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(255,257,'CH','电子不停车收费系统(ETC）通过车载电子标签与收费站ETC车道上的微波天线进行专用短程通讯，识别车辆有效后，通过计算机联网技术与银行进行结算处理，完成交易后，系统控制栏杆抬起，通行信号变绿，车辆通过后，栏杆自动回落，信号灯变红。下列有关ETC信息系统的说法中，错误的是_____。','[{"label": "A", "value": "车辆识别属于该系统的输入功能"}, {"label": "B", "value": "银行结算软件是应用系统软件"}, {"label": "C", "value": "ETC信息系统由硬件、软件、数据、通信网络和用户组成"}, {"label": "D", "value": "利用计算机联网技术与银行进行结算处理属于数据输出功能"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(256,258,'CH','从保护个人隐私及信息安全的角度来看，下列做法正确的是_____。','[{"label": "A", "value": "小明在校门口看到免费发送矿泉水的宣传单，当即扫码并填写个人信息"}, {"label": "B", "value": "小明在朋友圈中发布了班级通讯录的截图"}, {"label": "C", "value": "小明选择国家中小学智慧教育平台查找学习资料"}, {"label": "D", "value": "小明在公共场所中发现未加密的Wi-Fi，随即连接"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(257,259,'CH','下列行为中，违背网络道德规范的是_____。','[{"label": "A", "value": "删除不常联系的QQ好友"}, {"label": "B", "value": "从网络上下载一份研究报告后，署上自己的名字作为自己的研究报告交给老师"}, {"label": "C", "value": "在微信朋友圈分享自己网购的生活用品"}, {"label": "D", "value": "经好友同意，将他的微信推送给另一个好友"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(258,260,'CH','为防止信息系统中的数据被破坏，可以采用数据加密技术，以下说法错误的是_____。','[{"label": "A", "value": "私钥加密算法中用于加密和解密的密钥是相同的"}, {"label": "B", "value": "公钥加密算法中加密密钥和解密密钥是不同的"}, {"label": "C", "value": "RSA算法是一种私钥加密算法"}, {"label": "D", "value": "数字签名使用公钥加密等算法，生成别人无法伪造的一段数字串"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(259,261,'CH','下列四个十进制整数中，能用八位二进制数表示的是_____。','[{"label": "A", "value": "258"}, {"label": "B", "value": "212"}, {"label": "C", "value": "305"}, {"label": "D", "value": "296"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(260,262,'CH','将一个时长为1分钟、采样频率为44.1kHz、量化位数为16、双声道未经压缩的Wave格式音频文件压缩为MP3格式文件，压缩后的MP3格式文件大小为940KB，则其压缩比约为_____。','[{"label": "A", "value": "11:1"}, {"label": "B", "value": "11:2"}, {"label": "C", "value": "11:4"}, {"label": "D", "value": "88:1"}]','TianJin',2025,'A');
