INSERT INTO questions VALUES(262,264,'CH','以下关于数据整理的描述中，错误的是_____。','[{"label": "A", "value": "数据的重复会导致数据分布变化"}, {"label": "B", "value": "数据的缺失会导致样本信息减少"}, {"label": "C", "value": "数据的异常增加了分析的难度"}, {"label": "D", "value": "数据整理的科学与否对数据分析的影响不大"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(263,265,'CH','下列关于词云的说法中，错误的是_____。','[{"label": "A", "value": "词云是目前常用的关键词可视化形式"}, {"label": "B", "value": "用词云可视化文本数据可以帮助人们快速地了解文本的内容和特征信息"}, {"label": "C", "value": "词云通常使用字体的大小和颜色表示关键词的重要程度或出现频次"}, {"label": "D", "value": "在词云中，字越大表示该关键词使用频率就越低"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(264,266,'CH','下面关于算法的描述中，错误的是_____。','[{"label": "A", "value": "算法是解决问题的方法和步骤"}, {"label": "B", "value": "算法有一个或多个的输出"}, {"label": "C", "value": "算法就是计算机程序"}, {"label": "D", "value": "算法的步骤必须是有限的"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(265,267,'CH',replace('下列算法展示了一台自动售货机出售一瓶矿泉水的工作流程：\n\n步骤1：等待接收货款\n\n步骤2：若投入货款达1.5元或以上，执行步骤3和4；否则返回步骤1\n\n步骤3：售出一瓶矿泉水\n\n步骤4：从接收货款中减去1.5元，退回余额\n\n关于这个算法错误的说法是_____。','\n',char(10)),'[{"label": "A", "value": "上述算法描述采用的是自然语言"}, {"label": "B", "value": "这台自动售货机出售的矿泉水每瓶1.5元"}, {"label": "C", "value": "上述算法描述中未使用选择结构"}, {"label": "D", "value": "这台自动售货机可以退回余额"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(266,268,'CH',replace('在Python语言中，下列程序段执行后，输出结果是_____。\n\nx,y,z=142,125,120\n\nres=0\n\nif x>y:\n\nres=x\n\nelif y>z:\n\nres+=z\n\nres-=5\n\nprint(res)','\n',char(10)),'[{"label": "A", "value": "115"}, {"label": "B", "value": "137"}, {"label": "C", "value": "140"}, {"label": "D", "value": "157"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(267,269,'CH',replace('在下列程序段中，while循环执行的次数为_____。\n\nk=1000\n\nwhile k>1:\n\nprint(k)\n\nk=k//2','\n',char(10)),'[{"label": "A", "value": "8"}, {"label": "B", "value": "9"}, {"label": "C", "value": "10"}, {"label": "D", "value": "11"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(268,270,'CH','某智能手机安装了鸿蒙系统(HarmonyOS)，其主板集成了处理器、存储器等芯片，下列说法正确的是_____。','[{"label": "A", "value": "鸿蒙系统是智能手机重要的应用软件"}, {"label": "B", "value": "处理器性能是智能手机性能的唯一指标"}, {"label": "C", "value": "存储器可以存放用户数据而不能存放应用程序"}, {"label": "D", "value": "智能手机可以被看作特殊用途的计算机，包括输入、处理、存储和输出等部分"}]','TianJin',2025,'D');
