INSERT INTO questions VALUES(270,272,'CH','下面不属于无线网络的接入方式的是_____。','[{"label": "A", "value": "移动通信网络接入"}, {"label": "B", "value": "Wi-Fi接入"}, {"label": "C", "value": "蓝牙技术"}, {"label": "D", "value": "无线投屏"}]','TianJin',2025,'');
INSERT INTO questions VALUES(271,273,'CH','下列关于使用互联网搜索并遴选有价值的数据和信息的说法中，错误的是_____。','[{"label": "A", "value": "使用不同的搜索引擎对相同关键词进行检索，得到的结果可能不同"}, {"label": "B", "value": "用HTML（超文本标记语言）可以描述网页中的文本、图像和超链接等元素"}, {"label": "C", "value": "使用搜索引擎搜索信息时，搜索到的信息不一定是有用的"}, {"label": "D", "value": "在搜索引擎中输入的关键字越少，搜索到的信息条目就越少"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(272,274,'CH','思维导图通常用于_____类型的任务。','[{"label": "A", "value": "记忆"}, {"label": "B", "value": "创新思维"}, {"label": "C", "value": "分析和解决问题"}, {"label": "D", "value": "以上所有类型"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(273,275,'CH','小明通过国家中小学智慧教育平台进行物理课程学习，他利用信息技术手段将物理课本中的概念、方法等内容做成思维导图，并制作了一个演示动画，同时通过网络分享给其他同学。这体现了数字化学习的_____特点。','[{"label": "A", "value": "资源丰富"}, {"label": "B", "value": "形式多样"}, {"label": "C", "value": "可创造再生"}, {"label": "D", "value": "以上都是"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(274,276,'CH','小明回到家，对智能语音助手发出指令："小智，小智，打开空调，把温度设置为26℃"，其中"26"和"26℃"分别是_____。','[{"label": "A", "value": "数据、知识"}, {"label": "B", "value": "知识、智慧"}, {"label": "C", "value": "智慧、数据"}, {"label": "D", "value": "数据、信息"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(275,277,'CH','某年暑期（7、8月）全国边检机关共计保障1.1亿人次中外人员出入境，日均177.9万人次，较去年同期增长30.0%，环比5、6月份增长13.0%。结合上述文字信息，下列说法错误的是_____。','[{"label": "A", "value": "该信息中呈现的数据有文字类型和数字类型"}, {"label": "B", "value": "该信息对所有人来说价值都很高"}, {"label": "C", "value": "该信息可以被共享"}, {"label": "D", "value": "该信息可以被传递"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(276,278,'CH',replace('数据经处理后转换为相应的信息，人们将信息提炼归纳后内化为知识，知识被人们综合运用解决问题逐渐升华为智慧。可以用DIKW模型（如图所示）表示数据、信息、知识和智慧之间的递进关系，该模型共有四层，其中数据位于_____。\n\n![](media/image32.jpeg){width="3.076388888888889in"\nheight="2.548611111111111in"}','\n',char(10)),'[{"label": "A", "value": "第一层（底层）"}, {"label": "B", "value": "第二层"}, {"label": "C", "value": "第三层"}, {"label": "D", "value": "顶层"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(277,279,'CH',replace('下列信息技术应用场景中可能使用大数据技术的是_____。\n\n①为了避免堵车，司机利用电子导航地图查看道路拥堵情况\n\n②线上购物平台基于用户购买行为，向其推荐感兴趣的产品\n\n③家中的温湿度计实时显示当前室内温度和湿度\n\n④气象部门及时处理气象卫星等设备采集到的数据实现精准天气预报\n\n⑤智能交通系统根据车流量和人流量的实时数据自动调整信号灯时长','\n',char(10)),'[{"label": "A", "value": "①②③④"}, {"label": "B", "value": "①②④⑤"}, {"label": "C", "value": "②③④⑤"}, {"label": "D", "value": "①②③④⑤"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(278,280,'CH','自然语言处理技术是计算机科学和人工智能领域中的一个重要方向，下列不属于其研究领域的是_____。','[{"label": "A", "value": "语义理解"}, {"label": "B", "value": "问答系统"}, {"label": "C", "value": "欣赏音乐"}, {"label": "D", "value": "机器翻译"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(279,281,'CH','物联网架起了虚拟世界与现实世界相连接的桥梁，是信息技术领域的一次重大变革，以下不属于物联网应用的是_____。','[{"label": "A", "value": "利用智能物流系统实时查看快递运输情况"}, {"label": "B", "value": "利用微信在班级群中发布通知"}, {"label": "C", "value": "利用可穿戴设备同步健康数据"}, {"label": "D", "value": "利用智能家居系统自动调整室内灯光亮度"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(280,282,'CH','信息系统包含四个关键要素：人、信息技术、数据（大数据）和过程。其中，信息系统操作的对象是_____，它也是信息系统提供决策依据的来源。','[{"label": "A", "value": "人"}, {"label": "B", "value": "信息技术"}, {"label": "C", "value": "数据（大数据）"}, {"label": "D", "value": "过程"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(281,283,'CH','下列关于信息系统安全防范的说法，错误的是_____。','[{"label": "A", "value": "防火墙可以由软件构成，也可以由硬件构成"}, {"label": "B", "value": "定期对信息系统中的数据进行备份，可以避免数据的丢失"}, {"label": "C", "value": "只要用补丁程序修补了已暴露的系统漏洞，就可以保证信息系统一直安全运行"}, {"label": "D", "value": "身份认证可以防止未授权的用户私自访问信息系统"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(282,284,'CH','每个使用互联网的用户都是自媒体的发布者和参与者，可以说"人人都是通讯员，人人皆为传播者"。下列关于自媒体的说法，错误的是_____。','[{"label": "A", "value": "自媒体给信息的传播带来了巨大的便利"}, {"label": "B", "value": "自媒体时代可以进行社会舆论监督、反映社情民意"}, {"label": "C", "value": "使用自媒体发布信息时，要自觉遵守网络文明礼仪、道德准则以及国家的法律法规"}, {"label": "D", "value": "使用自媒体时，可以依据个人意愿转发信息，不会违反法律法规"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(283,285,'CH','常用的压缩方法分为无损压缩和有损压缩。无损压缩指对压缩后的数据进行还原后，得到的数据与压缩前完全相同；有损压缩指在压缩过程中会损失一定的信息，压缩后的数据无法还原成压缩前的样子。以下选项中属于无损压缩文件格式的是_____。','[{"label": "A", "value": "mpg"}, {"label": "B", "value": "jpg"}, {"label": "C", "value": "zip"}, {"label": "D", "value": "mp3"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(284,286,'CH',replace('在模拟电路转换成数字电路的过程中，若规定电压高于2.4V为高电平，用"1"表示；低于2.4V为低电平，用"0"表示。则下图中的模拟电路转换为数字电路的编码结果为_____。\n\n![](media/image33.jpeg){width="4.911111111111111in"\nheight="3.1256944444444446in"}','\n',char(10)),'[{"label": "A", "value": "00111100"}, {"label": "B", "value": "01111100"}, {"label": "C", "value": "11111111"}, {"label": "D", "value": "00011100"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(285,287,'CH','小明录制了一首时长为3分20秒的歌曲，双声道，采样频率为44.1kHz，量化位数为16，存储格式为WAV文件，计算该文件存储容量大小的算式是_____。','[{"label": "A", "value": "![](media/image34.jpeg){width=\"4.423611111111111in\" height=\"0.6805555555555556in\"}"}, {"label": "B", "value": "![](media/image35.jpeg){width=\"4.284722222222222in\" height=\"0.7291666666666666in\"}"}, {"label": "C", "value": "![](media/image36.jpeg){width=\"4.395833333333333in\" height=\"0.7916666666666666in\"}"}, {"label": "D", "value": "![](media/image37.jpeg){width=\"4.243055555555555in\" height=\"0.6944444444444444in\"}"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(286,288,'CH','超市中，收银员用条码扫描器扫描商品的条形码进行结账，该操作主要用于_____。','[{"label": "A", "value": "采集数据"}, {"label": "B", "value": "加工数据"}, {"label": "C", "value": "整理数据"}, {"label": "D", "value": "分类数据"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(287,289,'CH',replace('某网约车平台司机接单服务数据如表所示，管理员在对该数据进行整理时，发现存在的问题主要是_____。\n\n![](media/image38.jpeg){width="5.1194444444444445in"\nheight="1.9097222222222223in"}','\n',char(10)),'[{"label": "A", "value": "数据缺失"}, {"label": "B", "value": "数据重复"}, {"label": "C", "value": "数据无关联"}, {"label": "D", "value": "数据类型不一致"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(288,290,'CH',replace('小明用Python语言编写程序，将某饭店顾客的评价反馈内容汇总后制成词云图，如图所示。下列说法正确的是_____。\n\n![](media/image39.png){width="4.277777777777778in"\nheight="3.295138888888889in"}','\n',char(10)),'[{"label": "A", "value": "要先对反馈内容进行特征提取，再分词"}, {"label": "B", "value": "需要使用jieba库对内容进行数据分析"}, {"label": "C", "value": "该词云图显示了顾客评价中的所有词语"}, {"label": "D", "value": "词语\"不错\"比\"满意\"的出现频率高"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(289,291,'CH','电热水壶的工作原理是当水达到一定温度时，会自动断电，停止加热。这一过程用到的算法控制结构是_____。','[{"label": "A", "value": "顺序结构"}, {"label": "B", "value": "选择结构"}, {"label": "C", "value": "循环结构"}, {"label": "D", "value": "树形结构"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(290,292,'CH','某智慧农业系统能够根据土壤湿度实施自动灌溉，当土壤湿度测量值≥设定值时，表示土壤湿润，不需要浇灌水，否则需要浇水。用流程图描述该智慧农业系统运行的过程，正确的是_____。','[{"label": "A", "value": "![](media/image40.jpeg){width=\"2.951388888888889in\" height=\"2.1597222222222223in\"}"}, {"label": "B", "value": "![](media/image41.jpeg){width=\"2.9027777777777777in\" height=\"2.0347222222222223in\"}"}, {"label": "C", "value": "![](media/image42.jpeg){width=\"2.9375in\" height=\"2.0972222222222223in\"}"}, {"label": "D", "value": "![](media/image43.jpeg){width=\"3.0631944444444446in\" height=\"1.9916666666666667in\"}"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(291,293,'CH',replace('有Python程序代码如下：\n\nlist1=[]\n\nfor i in range(1,21):\n\nif i%5==0:\n\nbreak\n\nlist1.append(i)\n\nprint(list1)\n\n该程序段执行后，列表list1中输出的内容是_____。','\n',char(10)),'[{"label": "A", "value": "[1,2,3,4]"}, {"label": "B", "value": "[1,6,11,16]"}, {"label": "C", "value": "[5,10,15,20]"}, {"label": "D", "value": "[1,2,3,4,6,7,8,9,11,12,13,14,16,17,18,19]"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(292,294,'CH','用枚举算法解决"找出所有各位数字之和等于5的六位数"这一问题，当枚举范围设为_____时，解决问题的效率最高。','[{"label": "A", "value": "从1到999999"}, {"label": "B", "value": "从100000到999999"}, {"label": "C", "value": "从1到500000"}, {"label": "D", "value": "从100004到500000"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(293,295,'CH','某品牌汽车搭载了"鸿蒙4.0"系统，"鸿蒙4.0"在软件系统中被称为_____。','[{"label": "A", "value": "操作系统"}, {"label": "B", "value": "智能系统"}, {"label": "C", "value": "导航系统"}, {"label": "D", "value": "通信系统"}]','TianJin',2025,'A');
INSERT INTO questions VALUES(294,296,'CH',replace('张明通过家里的Wi-Fi上网时发现信号很弱，以下方案中可以增强卧室网络信号的是_____。\n\n①换一个信号更强的无线路由器\n\n②给路由器换个插座\n\n③将无线路由器移动到离卧室更近的地方','\n',char(10)),'[{"label": "A", "value": "①②"}, {"label": "B", "value": "①③"}, {"label": "C", "value": "②③"}, {"label": "D", "value": "①②③"}]','TianJin',2025,'B');
INSERT INTO questions VALUES(295,297,'CH',replace('小明帮家里组建家庭无线网络，主要包括以下步骤，正确的顺序应该是_____。\n\n①设置无线路由器并连接因特网\n\n②打开"百度"网站，测试能否连通\n\n③将光调制解调器用双绞线连接至路由器的WAN端口\n\n④将ISP光纤接入光调制解调器\n\n⑤将家中的计算机和移动终端接入局域网','\n',char(10)),'[{"label": "A", "value": "①④③⑤②"}, {"label": "B", "value": "①②④⑤③"}, {"label": "C", "value": "②③④⑤①"}, {"label": "D", "value": "④③①⑤②"}]','TianJin',2025,'D');
INSERT INTO questions VALUES(296,298,'CH','小明登录"文心一言"网站，输入"我要制作一份学校机器人社团纳新的海报，请帮我绘制一张科技感十足的图片"，网站根据他的描述生成了图片。这个过程中主要应用了_____。','[{"label": "A", "value": "虚拟现实技术"}, {"label": "B", "value": "物联网技术"}, {"label": "C", "value": "人工智能技术"}, {"label": "D", "value": "区块链技术"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(297,299,'CH','在学习历史课程时，小明准备用思维导图来整理某一历史时期的重大事件、人物和影响。以下关于思维导图使用的说法中，错误的是_____。','[{"label": "A", "value": "思维导图可以清晰地呈现历史事件之间的逻辑关系"}, {"label": "B", "value": "使用不同颜色的线条和图形可以增强思维导图的视觉效果和记忆点"}, {"label": "C", "value": "思维导图中不同的分支节点之间不能建立关联"}, {"label": "D", "value": "思维导图的中心主题应该明确，各分支围绕中心主题逐层展开"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(298,300,'CH','小明是一名高中生，他经常使用数字化学习方式来辅助自己学习。以下关于数字化学习描述中，错误的是_____。','[{"label": "A", "value": "小明登录在线教育平台，观看名师讲解的数学课程视频，帮助自己更好地理解复杂的数学概念"}, {"label": "B", "value": "小明借助某应用程序，根据学习进度和练习情况为自己制定个性化的学习计划"}, {"label": "C", "value": "小明认为数字化学习方式十分便捷，可以完全替代传统课堂学习"}, {"label": "D", "value": "小明利用在线平台与同学讨论学习问题，提高了学习兴趣和参与度 **\\"}]','TianJin',2025,'C');
INSERT INTO questions VALUES(299,1,'TF','数据是描述事物的一种原始记录，经过处理后，数据就有可能转换为相应的信息。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(300,2,'TF','由于采集到的数据可能有缺失、重复或错误，这就需要进行必要的整理。数据整理通常是指对数据进行校验和标准化。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(301,3,'TF','互联网的广泛应用，产生和传播着大量的数据，它包括了人们发布的文本、图像、音频和视频等文件，也包括了人们在上网过程中所记录的浏览日志、点击流量，以及通过传感器所采集的声、光和温度等数据。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(302,4,'TF','同一数据，具有不同知识、经验的人从不同的角度解读，会得到不同的信息。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(303,5,'TF','无论是信息还是知识，都来自于数据，都是以数据为载体而存在的。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(304,6,'TF','信息蕴含着价值，同一条信息对不同的信息接收者来说价值都是相同的。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(305,7,'TF','为了更好地发挥大数据的价值，就需要建立"用数据说话、用数据决策、用数据管理、用数据创新"的管理机制，以实现基于数据的科学决策。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(306,8,'TF','对于大数据而言，最基本、最重要的要求就是减少错误、保证质量。因此，大数据收集的信息量要尽量精确。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(307,9,'TF','大数据采集技术主要是通过物联网传感器、社交网络等方式获得各种类型海量数据。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(308,10,'TF','大数据所创造的价值密度是非常高的。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(309,11,'TF','无人作战飞机、无人潜航器、战场机器人等基于人工智能的无人机器能够自动搜索和跟踪目标，但不能自主识别地形并选择前进道路。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(310,12,'TF','人工智能的发展不会引发伦理道德问题，也不会给社会发展带来新的问题和冲击。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(311,13,'TF','信息系统是一个由人、软件、硬件、网络和数据资源等构成的人机系统。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(312,14,'TF','信息系统的主要目的和功能是对信息进行输入、处理、控制、存储、传输和输出，以支持作出快速合理的决策。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(313,15,'TF','智能家居系统是一个基于物联网的人工智能系统，不是一个信息系统。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(314,16,'TF','在一个信息系统中，可以只包括一种服务器，也可以包括多种服务器。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(315,17,'TF','信息系统中数据采集便利、来源丰富，但也会导致数据冗余或被闲置。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(316,18,'TF','信息系统一旦建设完成并开始运行后，就无法改造升级了。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(317,19,'TF','在信息社会中，信息资源的共享不应该有任何限制。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(318,20,'TF','对计算机中的文件进行加密，可以防止计算机感染病毒。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(319,21,'TF','计算机病毒、黑客攻击、数据存储介质损坏和个人失误都是威胁数据安全的因素。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(320,22,'TF','新买的电脑在第一次使用时，一定要先对操作系统进行安全漏洞修补，这样就可以保证电脑永远不会出现操作系统的安全隐患。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(321,23,'TF','身份认证是保护信息系统安全的第一道防线，用来防止未授权的用户私自访问系统。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(322,24,'TF','为防止信息系统被攻击，可以采用数字签名、数字水印等技术对数据进行加密。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(323,25,'TF','下列三张图片均是用画图软件生成，且尺寸均为60×30像素，并均保存为24位位图，其中所占存储空间最大的图片是red.bmp。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(324,26,'TF','在文档中我们可以对同一个汉字设置不同的字体，但在计算机内部对设置了不同字体的同一汉字的编码是相同的。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(325,27,'TF','与二进制数1010100101值相等的十六进制数是A25。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(326,28,'TF','十进制数245转换为二进制数，表示为11010101。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(327,29,'TF','ASCII编码是用1个字节表示英文字母、数字和常见字符的。',NULL,'TianJin',2025,'T');
INSERT INTO questions VALUES(328,30,'TF','在计算机中，RGB(Red,Green,Blue)颜色值通常用十六进制颜色码表示，如颜色值RGB(64,224,208)对应的颜色码是#42E0D0。',NULL,'TianJin',2025,'F');
INSERT INTO questions VALUES(329,31,'TF','网络爬虫是搜索引擎的重要组成部分，它通过互联网网页上的链接进入网站，采集网站页面内容，并将采集的结果直接返回给用户，从而实现快速检索。',NULL,'TianJin',2025,'F');
